// Shared Branding Configuration - Accessible from both main and renderer processes
// Edit these values to customize the app for your business

export interface BrandingConfig {
  // Company Information
  company: {
    name: string;
    fullName: string;
    cui: string; // CUI/Registration number
    email: string;
    phone: string;
    address?: {
      street?: string;
      city?: string;
      country?: string;
    };
  };

  // Application Branding
  app: {
    name: string;
    title: string;
    description: string;
    version: string;
    appId: string; // Electron app ID
  };

  // Visual Identity
  visual: {
    logo: {
      uri: string; // Base64 encoded logo or file path
      alt: string;
      height: string; // CSS height value (e.g., "40px", "2.5rem")
    };
    colors: {
      primary: string;    // Main accent color (replaces blue)
      secondary?: string; // Optional secondary color
      success?: string;   // Success color (green)
      warning?: string;   // Warning color (yellow)
      error?: string;     // Error color (red)
    };
  };

  // PDF Settings
  pdf: {
    filename: string; // Base filename for PDFs (without extension)
    headerTitle: string; // Title shown in PDF header
  };
}

