// Helper function to generate CSS custom properties from colors
export const generateColorVariables = (colors: BrandingConfig['visual']['colors']): string => {
  return `
    :root {
      --color-primary: ${colors.primary};
      --color-primary-50: ${colors.primary}08;
      --color-primary-100: ${colors.primary}1a;
      --color-primary-200: ${colors.primary}33;
      --color-primary-300: ${colors.primary}4d;
      --color-primary-400: ${colors.primary}66;
      --color-primary-500: ${colors.primary};
      --color-primary-600: ${adjustColorBrightness(colors.primary, -20)};
      --color-primary-700: ${adjustColorBrightness(colors.primary, -30)};
      --color-primary-800: ${adjustColorBrightness(colors.primary, -40)};
      --color-primary-900: ${adjustColorBrightness(colors.primary, -60)};
      ${colors.secondary ? `--color-secondary: ${colors.secondary};` : ''}
      ${colors.success ? `--color-success: ${colors.success};` : ''}
      ${colors.warning ? `--color-warning: ${colors.warning};` : ''}
      ${colors.error ? `--color-error: ${colors.error};` : ''}
    }
  `;
};

// Generate CSS variables object for React styles
export const generateColorVariablesObject = (colors: BrandingConfig['visual']['colors']) => {
  const variables: Record<string, string> = {};
  
  if (colors.primary) {
    variables['--color-primary'] = colors.primary;
    variables['--color-primary-600'] = adjustColorBrightness(colors.primary, -20);
    variables['--color-primary-700'] = adjustColorBrightness(colors.primary, -30);
  }
  
  if (colors.secondary) {
    variables['--color-secondary'] = colors.secondary;
  }
  
  if (colors.success) {
    variables['--color-success'] = colors.success;
  }
  
  if (colors.warning) {
    variables['--color-warning'] = colors.warning;
  }
  
  if (colors.error) {
    variables['--color-error'] = colors.error;
  }
  
  return variables;
};

// Helper function to adjust color brightness
function adjustColorBrightness(hex: string, percent: number): string {
  const num = parseInt(hex.replace("#", ""), 16);
  const amt = Math.round(2.55 * percent);
  const R = (num >> 16) + amt;
  const G = (num >> 8 & 0x00FF) + amt;
  const B = (num & 0x0000FF) + amt;
  return "#" + (0x1000000 + (R < 255 ? R < 1 ? 0 : R : 255) * 0x10000 +
    (G < 255 ? G < 1 ? 0 : G : 255) * 0x100 +
    (B < 255 ? B < 1 ? 0 : B : 255)).toString(16).slice(1);
}